1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const DEDUCTIBLE = 100;
59	const CAP_MULTIPLIER = 2;
60	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
62	const CURSED_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	const FIRST_INSURANCE_RATE = 0.1;
66	const LOYALTY_DISCOUNT_RATE = 0.2;
67	const LOYALTY_YEARS_THRESHOLD = 2;
68	const FOLLOWUP_DISCOUNT_RATE = 0.15;
69	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
70	  sword: 100,
71	  amulet: 60,
72	  staff: 80,
73	  potion: 40,
74	  rune: 25,
75	  moonstone: 25,
76	};
77	
78	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUM_BY_TYPE));
88	
89	const insuranceValue = (item: Item): number =>
90	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
91	
92	const insuranceSum = (items: Item[]): number =>
93	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
94	
95	const basePremium = (item: Item): number =>
96	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
97	
98	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
99	
100	const groupByType = (items: Item[]): Map<string, Item[]> => {
101	  const groups = new Map<string, Item[]>();
102	  for (const item of items) {
103	    const existing = groups.get(item.type) ?? [];
104	    existing.push(item);
105	    groups.set(item.type, existing);
106	  }
107	  return groups;
108	};
109	
110	const sumBasePremiums = (items: Item[]): number =>
111	  items.reduce((sum, item) => sum + basePremium(item), 0);
112	
113	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
114	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
115	
116	const groupTotal = (type: string, group: Item[]): number =>
117	  isCompleteComponentBlock(type, group)
118	    ? COMPONENT_BLOCK_PRICE
119	    : sumBasePremiums(group);
120	
121	const policyBase = (items: Item[]): number =>
122	  Array.from(groupByType(items)).reduce(
123	    (sum, [type, group]) => sum + groupTotal(type, group),
124	    0,
125	  );
126	
127	const perItemSurcharge = (
128	  items: Item[],
129	  predicate: (item: Item) => boolean,
130	  rate: number,
131	): number =>
132	  items
133	    .filter(predicate)
134	    .reduce((sum, item) => sum + basePremium(item) * rate, 0);
135	
136	const isCursed = (item: Item): boolean => item.cursed === true;
137	
138	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
139	
140	const isHighlyEnchanted = (item: Item): boolean =>
141	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
142	
143	const firstInsuranceSurcharge = (base: number): number =>
144	  base * FIRST_INSURANCE_RATE;
145	
146	const loyaltyDiscount = (base: number, customer: Customer): number =>
147	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
148	    ? base * LOYALTY_DISCOUNT_RATE
149	    : 0;
150	
151	const followupDiscount = (base: number, quoteIndex: number): number =>
152	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
153	
154	const totalSurcharges = (items: Item[], base: number): number =>
155	  perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
156	  perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
157	  firstInsuranceSurcharge(base);
158	
159	const totalDiscounts = (
160	  base: number,
161	  customer: Customer,
162	  quoteIndex: number,
163	): number =>
164	  loyaltyDiscount(base, customer) + followupDiscount(base, quoteIndex);
165	
166	const quotePremium = (
167	  items: Item[],
168	  customer: Customer,
169	  quoteIndex: number,
170	): number => {
171	  const base = policyBase(items);
172	  const adjusted =
173	    base +
174	    totalSurcharges(items, base) -
175	    totalDiscounts(base, customer, quoteIndex);
176	  return Math.ceil(adjusted) + PROCESSING_FEE;
177	};
178	
179	interface Policy {
180	  items: Item[];
181	  remainingCap: number;
182	}
183	
184	interface ScenarioState {
185	  customer: Customer;
186	  policies: Map<number, Policy>;
187	  quoteIndex: number;
188	  stepIndex: number;
189	}
190	
191	const validateItemTypes = (items: Item[]): void => {
192	  for (const item of items) {
193	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
194	      throw new Error(`unknown item type: ${item.type}`);
195	    }
196	  }
197	};
198	
199	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
200	  validateItemTypes(step.items);
201	  state.policies.set(state.stepIndex, {
202	    items: step.items,
203	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
204	  });
205	  const premium = quotePremium(step.items, state.customer, state.quoteIndex);
206	  state.quoteIndex += 1;
207	  return { premium };
208	};
209	
210	const reimbursementRate = (item: Item): number =>
211	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
212	    ? HIGH_ENCHANTMENT_CLAIM_RATE
213	    : 1;
214	
215	const damagePayout = (damage: Damage, items: Item[]): number => {
216	  const item = items.find((it) => it.type === damage.itemType) as Item;
217	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
218	};
219	
220	const countBy = <T>(items: T[], key: (item: T) => string): Map<string, number> => {
221	  const counts = new Map<string, number>();
222	  for (const item of items) {
223	    const k = key(item);
224	    counts.set(k, (counts.get(k) ?? 0) + 1);
225	  }
226	  return counts;
227	};
228	
229	const validateNonNegativeAmounts = (damages: Damage[]): void => {
230	  for (const damage of damages) {
231	    if (damage.amount < 0) {
232	      throw new Error(`claim damage amount must be non-negative`);
233	    }
234	  }
235	};
236	
237	const validateCoverage = (damages: Damage[], items: Item[]): void => {
238	  const itemCounts = countBy(items, (item) => item.type);
239	  const damageCounts = countBy(damages, (damage) => damage.itemType);
240	  for (const [type, count] of damageCounts) {
241	    if (count > (itemCounts.get(type) ?? 0)) {
242	      throw new Error(
243	        `claim damages exceed policy coverage for itemType ${type}`,
244	      );
245	    }
246	  }
247	};
248	
249	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
250	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
251	
252	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
253	  const policy = state.policies.get(step.policy) as Policy;
254	  const { damages } = step.incident;
255	  validateNonNegativeAmounts(damages);
256	  validateCoverage(damages, policy.items);
257	  const rawPayout = sumDamagePayouts(damages, policy.items);
258	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
259	  policy.remainingCap -= payout;
260	  return { payout, remainingCap: policy.remainingCap };
261	};
262	
263	const processStep = (step: Step, state: ScenarioState): StepResult =>
264	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
265	
266	export const processScenario = (scenario: Scenario): ScenarioOutput => {
267	  const state: ScenarioState = {
268	    customer: scenario.customer,
269	    policies: new Map<number, Policy>(),
270	    quoteIndex: 0,
271	    stepIndex: 0,
272	  };
273	  const results: StepResult[] = scenario.steps.map((step, stepIndex) => {
274	    state.stepIndex = stepIndex;
275	    return processStep(step, state);
276	  });
277	  return { results };
278	};
