3	const readStdin = async (): Promise<string> => {
4	  const chunks: Buffer[] = [];
5	  for await (const chunk of process.stdin) {
6	    chunks.push(chunk as Buffer);
7	  }
8	  return Buffer.concat(chunks).toString("utf8");
9	};
10	
11	const main = async (): Promise<void> => {
12	  try {
13	    const input = await readStdin();
14	    const scenario = JSON.parse(input) as Scenario;
15	    const output = processScenario(scenario);
16	    process.stdout.write(JSON.stringify(output));
17	  } catch (err) {
18	    process.stderr.write(
19	      err instanceof Error ? err.message : String(err),
20	    );
21	    process.exit(1);
22	  }
23	};
24	
25	void main();
